<template><div><PageHeader eyebrow="ADMIN / USERS" title="用户管理" description="查看账户、封禁解封、重置密码和分配角色"/><el-table v-loading="loading" :data="page.list" stripe><el-table-column prop="id" label="ID" min-width="170"/><el-table-column prop="username" label="用户名"/><el-table-column prop="nickname" label="昵称"/><el-table-column prop="email" label="邮箱" min-width="180"/><el-table-column label="角色"><template #default="{row}"><el-tag v-for="r in row.roles" :key="r" :type="r==='ADMIN'?'danger':''">{{ r }}</el-tag></template></el-table-column><el-table-column label="状态"><template #default="{row}"><el-tag :type="row.status===1?'success':'danger'">{{ row.status===1?'正常':'封禁' }}</el-tag></template></el-table-column><el-table-column label="操作" width="310" fixed="right"><template #default="{row}"><el-button size="small" @click="openDetail(row)">详情</el-button><el-button size="small" :type="row.status===1?'danger':'success'" @click="toggleBan(row)">{{ row.status===1?'封禁':'解封' }}</el-button><el-button size="small" @click="reset(row)">重置密码</el-button><el-button size="small" @click="roles(row)">角色</el-button></template></el-table-column></el-table><div class="pagination-wrap"><el-pagination background :total="page.total" :page-size="size" v-model:current-page="current" @current-change="load"/></div><el-drawer v-model="drawer" title="用户详情" size="480"><pre class="json-view">{{ JSON.stringify(detail,null,2) }}</pre><el-divider>操作日志</el-divider><el-timeline><el-timeline-item v-for="l in logs" :key="l.id" :timestamp="l.createdAt">{{ l.actionType||l.operationType }}：{{ l.description||l.detail }}</el-timeline-item></el-timeline></el-drawer></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import { ElMessageBox } from 'element-plus';import PageHeader from '../../components/PageHeader.vue';import { userApi } from '../../api/user';import { normalizePage } from '../../utils/page';const loading=ref(false),current=ref(1),size=10,page=reactive({list:[],total:0}),drawer=ref(false),detail=ref({}),logs=ref([]);async function load(){loading.value=true;try{Object.assign(page,normalizePage(await userApi.adminPage({page:current.value-1,size})))}finally{loading.value=false}}async function toggleBan(row){if(row.status===1){const {value}=await ElMessageBox.prompt('请输入封禁原因','封禁用户');await userApi.ban(row.id,value)}else await userApi.unban(row.id);load()}async function reset(row){const {value}=await ElMessageBox.prompt('请输入新密码','重置密码',{inputType:'password'});await userApi.resetPassword(row.id,value)}async function roles(row){const {value}=await ElMessageBox.prompt('输入角色，用逗号分隔，例如 USER,ADMIN','分配角色',{inputValue:(row.roles||[]).join(',')});await userApi.assignRoles(row.id,value.split(',').map(v=>v.trim()).filter(Boolean));load()}async function openDetail(row){detail.value=await userApi.adminDetail(row.id);logs.value=await userApi.logs(row.id);drawer.value=true}onMounted(load)</script>
